php bin/mnb-scraper source:sitemap https://example.com/sitemap.xml --format=txt --output=storage/{{project_name}}/sitemap-urls.txt
php bin/mnb-scraper bulk:crawl urls.txt --profile=seo --pipeline --job-dir=storage/{{project_name}}
php bin/mnb-scraper report:summary storage/{{project_name}} --format=html --output=storage/{{project_name}}/summary.html
